import React, { useState } from 'react';
import { Button, Text, View } from 'react-native';
import { BiometricAuthentication } from 'react-native-biometrics';
import AsyncStorage from '@react-native-community/async-storage';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleBiometricLogin = async () => {
    try {
      const result = await BiometricAuthentication.authenticate({
        promptMessage: 'Authenticate using Face ID or Fingerprint',
      });

      if (result.success) {
        await AsyncStorage.setItem('isAuthenticated', 'true');
        setIsAuthenticated(true);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handlePasswordLogin = async () => {
    // Implement password login logic here
  };

  if (isAuthenticated) {
    return <Text>Authenticated!</Text>;
  }

  return (
    <View>
      <Button title="Biometric Login" onPress={handleBiometricLogin} />
      <Button title="Password Login" onPress={handlePasswordLogin} />
    </View>
  );
};

export default App;